import { useParams, Link } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'

/**
 * /legal/:doc — единая страница для Политики / Оферты / Контактов / Поддержки.
 * Контент — заглушки для MVP, реальный текст утверждается юристом.
 */

type Doc = 'privacy' | 'terms' | 'contacts' | 'support'

const DOCS: Record<Doc, { title: string; updated: string; body: string }> = {
  privacy: {
    title: 'Политика обработки персональных данных',
    updated: '2026-04-23',
    body: `Оператор: ООО «Эдюсон Kids» (ИНН/ОГРН дозаполним при регистрации).
Юр. адрес: РФ.
Контакт DPO: privacy@eduson.kids

Цели обработки ПДн:
— регистрация и аутентификация ученика/родителя;
— отслеживание учебного прогресса (уроки, квизы, достижения);
— отправка отчётов родителю (при согласии);
— выставление счетов и учёт платежей.

Правовые основания: согласие субъекта (ФЗ-152 ч.1 ст.6), исполнение договора, закон.

Перечень обрабатываемых ПДн:
— имя ребёнка (псевдоним допускается);
— email родителя (при наличии);
— прогресс обучения (уроки, время, результаты квизов);
— опционально: VK ID при подключении отчётов;
— технические: IP, cookies, user-agent.

Передача третьим лицам: хостинг (GitHub Pages для статики, Yandex Cloud для функций), платёжные операторы (ЮKassa, CloudPayments) только для оплаты.

Срок хранения: 5 лет с момента последней активности или до запроса об удалении.

Права субъекта (ст. 14, 20, 21 ФЗ-152):
— доступ к своим ПДн, получение копии;
— изменение, удаление, блокировка;
— отзыв согласия.

Запросы: privacy@eduson.kids. Ответ — в течение 30 дней.

Данная политика актуальна на 2026-04-23 и может обновляться. Изменения публикуются на этой странице.`,
  },
  terms: {
    title: 'Пользовательское соглашение · Оферта',
    updated: '2026-04-23',
    body: `Публичная оферта ООО «Эдюсон Kids».

1. Предмет. Оператор предоставляет Пользователю (родителю/законному представителю ребёнка 9–15 лет) доступ к образовательной платформе «Эдюсон Kids» с курсами программирования.

2. Регистрация. Оператор не собирает ПДн ребёнка младше 14 лет без согласия родителя.

3. Стоимость и порядок оплаты.
— Подписка: 5 937 ₽/мес с автосписанием. Отмена — в 1 клик в /billing, без комиссии.
— Рассрочка: 71 244 ₽ за 48 уроков на 12 месяцев через банк-партнёр.
— Дополнительные пакеты уроков: фиксированная цена.

4. Возврат. Пользователь вправе вернуть уплаченную сумму в течение 14 дней с момента первого списания, если уроки не пройдены (ст.32 ЗоЗПП).

5. Интеллектуальная собственность. Курсы, 3D-модели, код платформы — собственность Оператора. Работы ученика (миры, сайты, скрипты) — собственность ученика.

6. Ответственность. Оператор обеспечивает работоспособность платформы 99,5% времени. Компенсация за простой — пропорциональное продление подписки.

7. Конфиденциальность. Обработка ПДн — согласно Политике на /legal/privacy.

Оферта действует с момента первого входа в платформу. Продолжение использования означает принятие условий.`,
  },
  contacts: {
    title: 'Контакты',
    updated: '2026-04-23',
    body: `ООО «Эдюсон Kids»

Email поддержки: help@eduson.kids
Email по приватности: privacy@eduson.kids
Email для B2B/школ: schools@eduson.kids

Телефон поддержки: появится после регистрации юрлица — сейчас все вопросы через email.

Юридический адрес и реквизиты (ИНН/КПП/ОГРН/р-с) появятся после регистрации юрлица. До тех пор — связь только через email-адреса выше.`,
  },
  support: {
    title: 'Поддержка',
    updated: '2026-04-23',
    body: `Проблема? Сначала глянь Никселя справа-снизу — часто помогает. Если не помог:

— Email: help@eduson.kids
— Telegram: @eduson_kids_help (подключение — Q2 2026)
— Форма обратной связи: ниже (Q2 2026)

Время ответа: до 24 часов в будние дни.

Типичные вопросы:
— Не ставится блок в Студии → проверь, что выбран инструмент «Поставить» (B).
— Не прогружаются модели → Ctrl+Shift+R (жёсткий reload).
— Не списать оплату → пиши на help@eduson.kids, решим вручную.`,
  },
}

export default function Legal() {
  const { doc } = useParams<{ doc: string }>()
  const entry = doc && doc in DOCS ? DOCS[doc as Doc] : null

  return (
    <PlatformShell>
      <section className="kb-cover" style={{ marginBottom: 32 }}>
        <div className="kb-cover-meta">
          <span className="eyebrow">Эдюсон Kids</span>
          <span className="kb-cover-meta-row">
            <span>v1.0</span>
            <span className="dot" />
            <span>2026</span>
          </span>
        </div>
        <h1 className="kb-cover-title kb-cover-title--md">
          {entry?.title ?? 'Правовые документы'}
        </h1>
        {entry && (
          <p className="kb-cover-sub" style={{ fontSize: 14 }}>
            Обновлено: {entry.updated}
          </p>
        )}
      </section>

      {!entry && (
        <section className="kb-card" style={{ padding: 24 }}>
          <p>Выбери раздел:</p>
          <ul style={{ listStyle: 'none', padding: 0, display: 'grid', gap: 8, marginTop: 16 }}>
            {(Object.keys(DOCS) as Doc[]).map((k) => (
              <li key={k}>
                <Link
                  to={`/legal/${k}`}
                  style={{
                    display: 'block',
                    padding: '12px 16px',
                    background: 'var(--paper-2, #F4EFE3)',
                    borderRadius: 10,
                    textDecoration: 'none',
                    color: 'var(--ink)',
                    fontWeight: 600,
                  }}
                >
                  {DOCS[k].title} →
                </Link>
              </li>
            ))}
          </ul>
        </section>
      )}

      {entry && (
        <section className="kb-card" style={{ padding: 32, maxWidth: 760 }}>
          <pre
            style={{
              whiteSpace: 'pre-wrap',
              wordWrap: 'break-word',
              fontFamily: 'var(--f-ui)',
              fontSize: 14,
              lineHeight: 1.65,
              color: 'var(--ink)',
              margin: 0,
            }}
          >
            {entry.body}
          </pre>
          <p style={{ marginTop: 24, fontSize: 12, color: 'var(--ink-soft)' }}>
            Это MVP-версия документа. Финальный текст утверждается юристом перед публичным релизом.
          </p>
        </section>
      )}
    </PlatformShell>
  )
}
